class Solution {
public:
    string reformatNumber(string number) {
        string digits;
        for (char c : number) {
            if (isdigit(c)) {
                digits += c;
            }
        }

        string result;
        int n = digits.size();

        for (int i = 0; i < n; i += 3) {
            if (n - i > 4) {
                result += digits.substr(i, 3) + "-";
            } else {
                if (n - i == 4) {
                    result += digits.substr(i, 2) + "-" + digits.substr(i + 2, 2);
                } else if (n - i == 3) {
                    result += digits.substr(i, 3);
                } else {
                    result += digits.substr(i, 2);
                }
                break;
            }
        }

        // Remove trailing dash if present
        if (!result.empty() && result.back() == '-') {
            result.pop_back();
        }

        return result;
    }
};
